func TestAxonBackend_UpdateMutatesAndPersists(t *testing.T) {
	t.Parallel()
	s, transport := newAxonStoreWithTransport(t)

	b := &Bead{Title: "to-update"}
	require.NoError(t, s.Create(b))

	require.NoError(t, s.Update(b.ID, func(bb *Bead) {
